import{_ as a,c as i,o as t,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Mejores prácticas: Activación, contexto y colaboración | Agent Skills","description":"Aprende a usar Agent Skills eficientemente. Domina la activación precisa, optimiza el contexto para ahorrar tokens, gestiona la colaboración de múltiples habilidades y mejora el rendimiento de respuestas de IA.","frontmatter":{"title":"Mejores prácticas: Activación, contexto y colaboración | Agent Skills","sidebarTitle":"Mejores prácticas","subtitle":"Mejores prácticas de uso","description":"Aprende a usar Agent Skills eficientemente. Domina la activación precisa, optimiza el contexto para ahorrar tokens, gestiona la colaboración de múltiples habilidades y mejora el rendimiento de respuestas de IA.","tags":["Mejores prácticas","Optimización de rendimiento","Mejora de eficiencia","Técnicas de uso de IA"],"prerequisite":["start-getting-started","start-installation"]},"headers":[],"relativePath":"es/vercel-labs/agent-skills/faq/best-practices/index.md","filePath":"es/vercel-labs/agent-skills/faq/best-practices/index.md"}'),o={name:"es/vercel-labs/agent-skills/faq/best-practices/index.md"};function r(l,e,n,c,d,u){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="mejores-practicas-de-uso" tabindex="-1">Mejores prácticas de uso <a class="header-anchor" href="#mejores-practicas-de-uso" aria-label="Permalink to &quot;Mejores prácticas de uso&quot;">​</a></h1><h2 id="lo-que-podras-hacer-al-terminar" tabindex="-1">Lo que podrás hacer al terminar <a class="header-anchor" href="#lo-que-podras-hacer-al-terminar" aria-label="Permalink to &quot;Lo que podrás hacer al terminar&quot;">​</a></h2><p>Al terminar esta lección, podrás:</p><ul><li>✅ Seleccionar con precisión palabras clave de activación, permitiendo que la IA active habilidades en el momento correcto</li><li>✅ Optimizar la gestión del contexto, reducir el consumo de tokens y mejorar la velocidad de respuesta</li><li>✅ Manejar escenarios de colaboración de múltiples habilidades, evitando conflictos y confusiones</li><li>✅ Dominar patrones de uso comunes para mejorar la eficiencia del trabajo</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p>Puedes haber encontrado estos escenarios:</p><ul><li>✗ Ingresas &quot;ayúdame a implementar&quot;, pero la IA no activa la habilidad Vercel Deploy</li><li>✗ La misma tarea activa múltiples habilidades, la IA no sabe cuál usar</li><li>✗ Las habilidades ocupan demasiado contexto, lo que hace que la IA &quot;olvide&quot; tus requerimientos</li><li>✗ Cada vez tienes que re-explicar la tarea, no sabes cómo hacer que la IA recuerde tus hábitos</li></ul><h2 id="cuando-usar-esta-tecnica" tabindex="-1">Cuándo usar esta técnica <a class="header-anchor" href="#cuando-usar-esta-tecnica" aria-label="Permalink to &quot;Cuándo usar esta técnica&quot;">​</a></h2><p>Cuando usas Agent Skills y encuentras:</p><ul><li>🎯 <strong>Activación inexacta</strong>: la habilidad no se activa o se activó la habilidad incorrecta</li><li>💾 <strong>Presión del contexto</strong>: las habilidades ocupan demasiados tokens, afectando otras conversaciones</li><li>🔄 <strong>Conflictos de habilidades</strong>: múltiples habilidades se activan simultáneamente, la ejecución de la IA es confusa</li><li>⚡ <strong>Rendimiento degradado</strong>: la respuesta de la IA se vuelve lenta, necesitas optimizar el método de uso</li></ul>',10)])])}const h=a(o,[["render",r]]);export{m as __pageData,h as default};
